//! E2e tests for category: table_operations

use kreuzberg::{cells_to_markdown, cells_to_text};

#[test]
fn test_cells_markdown_basic() {
    // Convert basic 2D cell array to markdown table format
    let cells_json = serde_json::json!("[[\"Name\",\"Age\"],[\"Alice\",\"30\"],[\"Bob\",\"25\"]]");
    let cells = serde_json::from_value(cells_json).unwrap();
    let result = cells_to_markdown(&cells).expect("should succeed");
    assert!(
        format!("{:?}", result.result).contains(r#"|"#),
        "expected to contain: {}",
        r#"|"#
    );
}

#[test]
fn test_cells_markdown_single() {
    // Convert single-column cell array to markdown table
    let cells_json = serde_json::json!("[[\"Header\"],[\"Value\"]]");
    let cells = serde_json::from_value(cells_json).unwrap();
    let _ = cells_to_markdown(&cells);
}

